# generated by AI in Github cloud

from __future__ import annotations

from collections.abc import Sequence
from typing import TextIO
import sys

DEFAULT_RECIPIENT = "World"
GREETING_TEMPLATE = "Hello {}"


def create_greeting(requested_recipient: str | None) -> str:
    recipient = DEFAULT_RECIPIENT if requested_recipient is None or requested_recipient.strip() == "" else requested_recipient.strip()
    return GREETING_TEMPLATE.format(recipient)


def greet(args: Sequence[str] | None) -> str:
    if args is None or len(args) == 0:
        return create_greeting(None)
    return create_greeting(args[0])


def main(args: Sequence[str] | None = None, output: TextIO | None = None) -> None:
    destination = output if output is not None else sys.stdout
    print(greet(args), file=destination)


if __name__ == "__main__":
    main(sys.argv[1:])
